var e=e=>{e.data(`mediaGalleryBundle`,()=>({selectedProduct:null,init(){window.addEventListener(`product-changed`,e=>{this.selectedProduct=e.detail.product,this.renderGallery(this.selectedProduct)})},async renderGallery(e){console.log(`renderGallery`,e);let t=document.querySelector(`[data-media-wrapper]`);if(!t){console.error(`mediaWrapper not found`);return}t.innerHTML=``;try{let n=await fetch(`/products/${e.handle}?view=bundle`);if(!n.ok)throw Error(`Failed to fetch gallery: ${n.status}`);let r=await n.text(),i=new DOMParser().parseFromString(r,`text/html`).querySelector(`[data-gallery-wrapper]`);if(!i){console.error(`newMediaInner not found`);return}t.innerHTML=i.innerHTML}catch(e){console.error(`error`,e)}}}))};export{e as default};